const top = $input.first().json || {};
const body = top.body || top;
const resource = (body && body.resource) || top.resource || {};
const eventData = (body && body.eventData) || top.eventData || {};
const dataset_id = resource.defaultDatasetId || body.defaultDatasetId || top.defaultDatasetId || '';
const run_id = resource.id || body.run_id || eventData.actorRunId || '';
const task_id = eventData.actorTaskId || body.task_id || top['X-Apify-Task-Id'] || '';
const tenant_id = body.tenant_id || top.tenant_id || '23610954-5fd0-482f-8eb0-11edce1f5c58';
const feature_id = body.feature_id || top.feature_id || '';
return [{ json: { dataset_id, run_id, task_id, tenant_id, feature_id, body, resource, eventData } }];

// FEAT-001 Google Play Rogue Apps classifier
const items = $input.all();
const ev = $('Webhook').item.json.body || {};
const headers = ev.headers || {};
const tenantId = headers['x-tenant-id'] || '23610954-5fd0-482f-8eb0-11edce1f5c58';
const taskId = ev.eventData?.actorTaskId || null;
const runId = ev.resource?.id || null;
const datasetId = ev.resource?.defaultDatasetId || null;

const OFFICIAL_DEV = 'CreditAccess Grameen Limited';
const OFFICIAL_APP_IDS = ['com.creditaccessgrameen.mahi'];
const HIGH_RISK_PERMS = [
  'android.permission.READ_SMS',
  'android.permission.READ_CONTACTS',
  'android.permission.SYSTEM_ALERT_WINDOW',
  'android.permission.BIND_ACCESSIBILITY_SERVICE',
];

const rows = [];
for (const itm of items) {
  const a = itm.json || {};
  const appId = a.appId || a.id || a.bundleId;
  if (!appId) continue;
  if (OFFICIAL_APP_IDS.includes(appId)) continue;
  const developer = a.developer || a.developerName || a.developer_id || '';
  if (developer === OFFICIAL_DEV) continue;

  const permissions = Array.isArray(a.permissions) ? a.permissions : [];
  const hasCriticalPerm = permissions.some(p => HIGH_RISK_PERMS.includes(p));

  const severity = hasCriticalPerm ? 'Critical' : 'Substantial';
  const confidence = hasCriticalPerm ? 0.95 : 0.7;
  const action = hasCriticalPerm ? 'takedown' : 'monitor';

  rows.push({
    tenant_id: tenantId,
    apify_task_id: taskId,
    apify_run_id: runId,
    apify_dataset_id: datasetId,
    feature_id: 'FEAT-001',
    source: 'apify:google-play',
    kind: 'fake_app',
    fraud_pattern: 'fake_app',
    severity,
    confidence,
    item_id: appId,
    url_or_value: `https://play.google.com/store/apps/details?id=${appId}`,
    evidence: {
      app_id: appId,
      title: a.title || a.name,
      developer,
      rating: a.score || a.rating,
      installs: a.installs || a.minInstalls,
      last_updated: a.updated || a.lastUpdated,
      permissions,
      brand_keyword_matched: a.searchTerm || a.query,
    },
    language_detected: a.language || null,
    matched_keywords: a.searchTerm ? [a.searchTerm] : [],
    timestamp_source: a.released || a.updated || null,
    ai_filtered: false,
    ai_reason: hasCriticalPerm
      ? 'Non-official developer + invasive permissions (SMS/Contacts/Overlay/Accessibility)'
      : 'Non-official developer using brand keyword',
    recommended_action: action,
  });
}
return [{ json: { rows, count: rows.length } }];
